import{_ as t,o as r,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"65. Flexible Working Arrangements","description":"","frontmatter":{"title":"65. Flexible Working Arrangements","eba":"Mental Health Services 2024-2028","topics":["flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.md","filePath":"ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.md"}'),s={name:"ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.md"};function a(i,e,l,g,p,h){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_65-flexible-working-arrangements" tabindex="-1">65. Flexible Working Arrangements <a class="header-anchor" href="#_65-flexible-working-arrangements" aria-label="Permalink to &quot;65. Flexible Working Arrangements&quot;">​</a></h1><p><strong>65.1</strong> The Act entitles a specified Employee to request flexible working arrangements in specified circumstances.</p><p><strong>65.2</strong> For the purposes of this clause 65, a long term casual Employee means a casual Employee (as defined in <a href="/eba/ebas/mental-health/common-terms/employment-types/25-modes-of-employment.html">clause 25.4</a>(b)) that has been employed by the Employer on a regular and systematic basis.</p><p><strong>65.3</strong> A specified Employee is a:</p><p><strong>(a)</strong> full-time or part-time Employee with at least 12 months’ continuous service; or</p><p><strong>(b)</strong> long term casual Employee with a reasonable expectation of continuing employment by the Employer on a regular and systematic basis.</p><p><strong>65.4</strong> The qualifying period at 65.3(a) will not apply in circumstances where the Employee demonstrates their circumstances have unexpectedly changed since commencement</p><p><strong>65.5</strong> The specified circumstances are if the Employee:</p><p><strong>(a)</strong> Is pregnant</p><p><strong>(b)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger</p><p><strong>(c)</strong> is a carer within the meaning of the Carer Recognition Act 2010 caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged</p><p><strong>(d)</strong> has a disability</p><p><strong>(e)</strong> is 55 years or older</p><p><strong>(f)</strong> is experiencing family and domestic violence; or</p><p><strong>(g)</strong> provides care or support to a member of the Employee’s immediate family or household, who requires care or support because the member is experiencing family and domestic violence.</p><p><strong>65.6</strong> A specified Employee may make a request to the Employer for a change in working arrangements relating to the circumstances at subclause 65.4.</p><p><strong>65.7</strong> A request for a flexible work arrangement includes (but is not limited to) a request to work part-time upon return to work after taking leave for the birth or adoption of a child to assist the Employee to care for the child (which may, for example, include a reduction in existing part-time hours).</p><p><strong>65.8</strong> Changes in working arrangements may include but are not limited to hours of work, patterns of work and location of work.</p><p><strong>65.9</strong> The request by the Employee must be in writing, set out the change sought and reasons for the change.</p><p><strong>65.10</strong> The Employer must give the Employee a written response to the request within 21 days, stating whether the Employer grants or refuses the request. A request may only be refused on reasonable business grounds as described in the NES. Note: The assertion of an inherent requirement does not, by itself, mean that this is a reasonable business ground to refuse a request for a flexible working arrangement.</p><p><strong>65.11</strong> Without limiting what are reasonable business grounds for the purposes of clause 65.10, reasonable business grounds include the following:</p><p><strong>(a)</strong> that the new working arrangements requested by the Employee would be too costly for the Employer</p><p><strong>(b)</strong> that there is no capacity to change the working arrangements of other Employees to accommodate the new working arrangements requested by the Employee</p><p><strong>(c)</strong> that it would be impractical to change the working arrangements of other Employees, or recruit new Employees, to accommodate the new working arrangements requested by the Employee</p><p><strong>(d)</strong> that the new working arrangements requested by the Employee would be likely to result in a significant loss in efficiency or productivity; and</p><p><strong>(e)</strong> that the new working arrangements requested by the Employee would be likely to have a significant negative impact on the Employer&#39;s operations.</p><p><strong>65.12</strong> Where the Employer refuses the request, the written response will include the following:</p><p><strong>(a)</strong> details of the reasons for the refusal, including the business grounds for refusing the request and how those grounds apply to the Employee&#39;s request</p><p><strong>(b)</strong> any other changes that the Employer is willing to make to accommodate the Employee&#39;s circumstances, if applicable</p><p><strong>(c)</strong> where there are no such changes available as contemplated by 65.12(b), state that there are no such changes; and</p><p><strong>(d)</strong> their right for the dispute to be resolved at the workplace level or by arbitration in accordance with clause 65.17 below.</p><p><strong>65.13</strong> Where a request for flexible work arrangements is made, the Employer must meet with the Employee to discuss:</p><p><strong>(a)</strong> the request</p><p><strong>(b)</strong> an alternative to the request; or</p><p><strong>(c)</strong> reasons for a refusal on reasonable business grounds.</p><p><strong>65.14</strong> At a meeting under clause 65.13, the Employer must genuinely try to reach agreement on a change in working arrangements that will reasonably accommodate the Employee&#39;s circumstances having regard to:</p><p><strong>(a)</strong> the needs of the Employee arising from the circumstances</p><p><strong>(b)</strong> the consequences for the Employee if changes in working arrangements are not made</p><p><strong>(c)</strong> any alternative flexibility arrangements that may meet the circumstances of the Employee that require flexibility; and</p><p><strong>(d)</strong> any reasonable grounds for refusing the request.</p><p><strong>65.15</strong> An Employee or Employer may choose to be represented at a meeting under subclause 65.13 by a representative including a Union or employer organisation.</p><p><strong>65.16</strong> If the Employer and the Employee reached an agreement under clause 65.13 on a change in working arrangements that differs from that initially requested by the Employee, the Employer must provide the Employee with a written response to their request setting out the agreed change(s) in working arrangements.</p><p><strong>65.17</strong> The Dispute Resolution Procedure in this Agreement will apply to any grievance / dispute arising in relation to a request for flexible working arrangements. Without limiting the Dispute Resolution Procedure in the Agreement at first instance, the Employer and Employee will attempt to resolve the dispute at the workplace level through discussion before it is referred to the FWC.</p><p><strong>65.18</strong> For the avoidance of doubt, clause 65.17 applies to the Employee in the event the Employer refuses their request, or 21 days have passed since their making the request and the Employer has not provided them with a written response under this Agreement.</p><p><strong>65.19</strong> Other entitlements relevant to family and domestic violence can be found at clause 45.</p><p>Plain language terms: flex work, flexible hours, work from home, WFH.</p>',46)])])}const u=t(s,[["render",a]]);export{c as __pageData,u as default};
